INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Multi-model chat$q$, $q$Switch between leading language models such as GPT-4o and Claude from a single You.com account instead of maintaining separate subscriptions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$ARI deep-research agent$q$, $q$A dedicated research agent that runs multi-step web research and compiles longer, cited reports for complex questions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Cited, source-linked answers$q$, $q$Chat responses include inline citations and links back to source pages rather than an unsourced summary.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Web Search API$q$, $q$A pay-as-you-go API returning real-time, LLM-ready search results with country and language targeting for developers building AI applications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Contents API$q$, $q$Extracts full page text or clean Markdown/HTML from one or many URLs in a single batch request.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Research API$q$, $q$A tiered research API (Lite through Frontier) that returns cited, multi-source research answers for complex queries.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Finance Research API$q$, $q$Structured financial research covering filings, macro data, and markets with traceable source references.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Image generation$q$, $q$Generate images directly from a chat prompt as part of the consumer plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Privacy-focused search$q$, $q$Search results and chat can be used without ad tracking, appealing to privacy-conscious users.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Web, extension, and mobile access$q$, $q$Available as a web app, browser extension, and mobile apps for iOS and Android.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Free tier gives access to multiple premium AI models without separate subscriptions$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Answers include inline citations, making it easier to verify claims than with an unsourced chatbot$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$ARI deep-research agent is useful for compiling longer, multi-source research reports$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Developer APIs (Search, Contents, Research, Finance Research) offer flexible, pay-as-you-go access to real-time web data$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$No-ad-tracking positioning appeals to privacy-conscious users$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Public reporting indicates the company has shifted strategic focus toward enterprise/API revenue, creating uncertainty about long-term consumer investment$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Higher-tier consumer plan (Max) and higher research API tiers are priced well above entry-level offerings$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Finance Research API pricing is high on a per-call basis compared to the base Search API$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Official consumer pricing information is less consistently published than the API pricing pages$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Smaller brand recognition and user base compared to major search engines and rival AI assistants$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$What is You.com?$q$, $q$You.com is an AI-powered search engine and chat assistant, founded in 2020, that combines conversational answers, multiple language models, and citation-backed results, alongside developer-facing web search and research APIs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Is You.com free to use?$q$, $q$Yes, You.com offers a free tier for its consumer chat and search product, with paid Pro and Max plans that unlock additional models, higher usage limits, and larger context windows.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Which AI models can I use on You.com?$q$, $q$You.com's consumer plans provide access to multiple leading language models, including options like GPT-4o and Claude, alongside You.com's own agents such as ARI for deep research.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Does You.com offer an API for developers?$q$, $q$Yes. You.com sells a Web Search API, Contents API, Research API, and Finance Research API on a pay-as-you-go basis, with a starting credit for new developer accounts.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Is You.com still a consumer search engine, or has it become an enterprise product?$q$, $q$You.com started as a consumer search engine and chatbot, and that product is still available, but the company has increasingly emphasized its enterprise and developer API business, particularly after its 2025 Series C funding round.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Comparing AI model outputs in one place$q$, $q$Ask the same question across multiple language models without maintaining separate accounts or subscriptions.$q$, $q$Students, researchers, and everyday knowledge workers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Building AI apps with grounded web search$q$, $q$Use the Search and Contents APIs to add real-time, citation-backed web data to a retrieval-augmented generation pipeline or AI agent.$q$, $q$Developers and AI engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Compiling cited research reports$q$, $q$Use the ARI agent or Research API to gather and summarize information from many sources into a single, sourced report.$q$, $q$Analysts, consultants, and research teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Financial and market research with sources$q$, $q$Query the Finance Research API for structured financial data, filings, and market information with traceable citations.$q$, $q$Financial analysts and fintech developers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Free$q$, $q$$0$q$, $q$Free$q$, $q$["Access to You.com chat and search","Basic model access","No ad tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Pro$q$, $q$$15/month (billed annually) or $20/month (billed monthly)$q$, $q$Monthly or annual$q$, $q$["Access to premium models such as GPT-4o and Claude","Unlimited writing and image generation","File uploads","Priority processing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Max$q$, $q$$200/month$q$, $q$Monthly$q$, $q$["Large context windows","Unlimited deep research reports (ARI)","Support for large documents and datasets"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$Developer API$q$, $q$From $5 per 1,000 calls (Search API)$q$, $q$Pay-as-you-go$q$, $q$["Web Search, Contents, Research, and Finance Research APIs","$100 free credit for new accounts","Volume and annual discounts","SOC 2 certified"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$You.com is an AI-powered search engine and assistant founded in 2020 by Richard Socher, Salesforce's former chief scientist, and Bryan McCann, a former Salesforce NLP researcher. Headquartered in Palo Alto, California, the company launched its public search engine in November 2021 with a privacy-first pitch: ad-free, non-tracked search results alongside a traditional results page, positioning itself as an alternative to Google for users who wanted more control over their data.$q$, $q$The product evolved quickly into a conversational AI platform. YouChat, launched in December 2022, was among the first chatbots to combine a large language model with live web results and citations. Subsequent updates added multimodal chat, image generation, and access to multiple leading models (including GPT-4o and Claude) from a single interface, plus ARI, a deep-research agent introduced in February 2025 that compiles longer, cited research reports from many sources in a single query.$q$, $q$By 2025-2026, You.com had layered an enterprise and developer business on top of its consumer chat product, offering a Web Search API, Contents API, Research API, and Finance Research API used by companies such as OpenAI, Amazon, Nvidia, Salesforce, and Databricks. A $100 million Series C round in 2025 valued the company at $1.5 billion, and reporting characterized the raise as part of a broader shift in emphasis from a seat-priced consumer search product toward usage-based retrieval and research infrastructure for AI applications, even as the free and paid consumer plans continued to operate.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$who-you-com-is-for$q$, $q$Who You.com Is For$q$, 2, ARRAY[$q$You.com suits people who want to try several frontier language models without juggling separate subscriptions. The free tier and Pro plan give access to models like GPT-4o and Claude alongside You.com's own agents, which appeals to power users, students, and researchers who compare model outputs or want one chat window for everyday questions, writing help, and quick web lookups with visible sources.$q$, $q$Developers and AI teams building retrieval-augmented generation, agents, or research tools are a strong fit, since the Search, Contents, and Research APIs provide low-latency, citation-backed web data that can be dropped into an existing LLM pipeline without building and maintaining a crawler or index.$q$, $q$It also works well for privacy-conscious searchers and for teams in regulated industries such as finance, compliance, and research that need sourced, verifiable answers rather than an unsourced chatbot response, since You.com emphasizes citations and traceable references across both its consumer chat and its research-oriented APIs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Casual users who only want a fast, familiar Google-style search box may find You.com's chat-first interface and model-switching options more than they need, and may prefer a simpler, single-purpose search engine instead.$q$, $q$Budget-conscious developers running high call volumes should look closely at the API pricing, particularly the Finance Research API at roughly $110 per 1,000 calls; costs can add up quickly compared to flatter-rate alternatives, and the higher research tiers (Deep, Exhaustive, Frontier) are priced well above the entry Lite tier.$q$, $q$Anyone who wants long-term certainty about a pure consumer product should also factor in the company's documented shift toward enterprise and developer revenue; while free and paid consumer plans remain available, You.com's public messaging and investment have increasingly centered on its API and enterprise business rather than the original consumer search engine.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of the consumer product is a multi-model chat interface that lets users switch between models such as GPT-4o and Claude, generate images, and get cited, source-linked answers instead of an unsourced summary, all from a single account.$q$, $q$ARI, You.com's deep-research agent, runs multi-step web research across many sources to produce longer cited reports for complex questions, and the company markets its Research API as a top performer on research-focused benchmarks such as DeepSearchQA.$q$, $q$For developers, the Web Search API and Contents API expose real-time search results and clean page text or Markdown extraction for feeding into other applications, while the Finance Research API adds structured financial data, filings, and market information with source traceability, all usable on a pay-as-you-go basis with volume and annual discounts.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', $q$the-you-com-experience$q$, $q$The You.com Experience$q$, 2, ARRAY[$q$Using You.com day to day feels like a hybrid between a search engine and a chatbot: queries return a conversational answer with inline citations plus, in many cases, a supporting results rail, and users can pick a model or a specialized mode such as writing, research, or coding before asking a question.$q$, $q$The product is available as a web app, a browser extension, and mobile apps, and the free tier is usable without a credit card, with upgrade prompts appearing mainly around premium model access, higher usage limits, and larger context windows on the paid Pro and Max tiers.$q$, $q$Overall, the experience reflects a company balancing two audiences at once: a still-functioning consumer AI assistant for everyday search and chat, and a maturing enterprise API platform for developers who need fast, cited, real-time web data inside their own AI products.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ea1262a4-d760-4eec-88e1-896425d5ac44', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
