INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Visual Sales Pipeline$q$, $q$Drag-and-drop deal management across one or more customizable pipelines and stages.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Contact & Deal Management$q$, $q$Centralized contact and company records with notes, documents, and a running activity feed.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Built-in Calling$q$, $q$Click-to-dial dialing with automatic call logging and call recording attached to the relevant contact.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Email Integration$q$, $q$Sync personal email accounts, track opens and clicks, and send templated messages from within a deal.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sales Reporting & Forecasting$q$, $q$Prebuilt and custom dashboards covering pipeline conversion, rep activity, and revenue forecasts.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$AI-Assisted Lead Scoring$q$, $q$Predictive scoring that helps reps prioritize leads most likely to convert.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Workflow Automation$q$, $q$Trigger-based task assignment, reminders, and follow-up sequences to keep deals moving.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Mobile CRM App$q$, $q$Full-featured iOS and Android apps with offline access and geolocation-based visit tracking for field reps.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Zendesk Support Integration$q$, $q$Shared customer records with Zendesk's help desk products for a unified sales and support view.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Open API & Integrations$q$, $q$A REST API plus a marketplace of prebuilt connectors to common sales and business tools.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Intuitive, visual pipeline interface that most reps can pick up with minimal training$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Full-featured native mobile apps carried over from Base CRM's mobile-first design$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Built-in calling, email tracking, and texting reduce the need for separate communication tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Tight integration with Zendesk's customer service products for a unified customer view$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Faster setup and gentler learning curve than many enterprise-grade CRMs$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Advanced features like forecasting, custom fields, and permissions are gated behind higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Customization and reporting flexibility lag behind dedicated CRMs like Salesforce or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Add-ons and tier upgrades can meaningfully raise the total per-seat cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Limited built-in marketing automation compared to platforms built for marketing-and-sales alignment$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Smaller third-party app ecosystem than larger, longer-established CRM platforms$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$What is Zendesk Sell?$q$, $q$Zendesk Sell is a cloud-based sales CRM from Zendesk that helps teams manage contacts, deals, and the sales pipeline, with built-in calling, email tracking, reporting, and mobile apps.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Is Zendesk Sell the same as Base CRM?$q$, $q$Yes. Zendesk Sell began as Base CRM, which Zendesk acquired in 2018 and rebranded as part of its customer experience platform.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Does Zendesk Sell offer a free trial?$q$, $q$Zendesk offers a free trial for Sell, giving prospective customers hands-on access to core CRM features before committing to a paid plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Can Zendesk Sell be used without Zendesk Support?$q$, $q$Yes, Sell works as a standalone sales CRM, though teams that also use Zendesk Support or the Zendesk Suite get the added benefit of shared customer records across sales and service.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$What is the difference between Zendesk Sell's pricing tiers?$q$, $q$Higher tiers unlock more advanced capabilities such as additional pipelines, sales forecasting, custom fields, advanced call analytics, and stricter role-based permissions, while the entry tier covers core CRM, email, and mobile functionality.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Managing a Multi-Stage Sales Pipeline$q$, $q$Reps track deals through a visual, drag-and-drop pipeline, keeping contact details, deal value, and activity history together in one deal record.$q$, $q$Small to mid-size sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Unifying Sales and Support Data$q$, $q$Companies running Zendesk Support alongside Sell can view a customer's sales and support history side by side without a separate integration.$q$, $q$Businesses already using Zendesk Support or Suite$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Supporting Field Sales Reps$q$, $q$The mobile app gives outside reps offline access, geolocation-based visit tracking, and full pipeline management away from a desk.$q$, $q$Field sales teams and outside account executives$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Forecasting Revenue and Pipeline Health$q$, $q$Sales managers use built-in dashboards and forecasting tools to spot pipeline bottlenecks and project expected revenue without building custom reports.$q$, $q$Sales managers and revenue operations teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Team$q$, $q$$19/user/month$q$, $q$Billed annually (higher on month-to-month)$q$, $q$["Core CRM contact and deal management","One customizable sales pipeline","Email integration","Click-to-dial calling and call recording","Fully featured mobile app"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Growth$q$, $q$$55/user/month$q$, $q$Billed annually (higher on month-to-month)$q$, $q$["Everything in Team","Advanced call analytics","Customizable fields","Sales forecasting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Professional$q$, $q$$115/user/month$q$, $q$Billed annually (higher on month-to-month)$q$, $q$["Everything in Growth","AI-powered lead scoring","Task and workflow automation","Bulk email sequences","Role-based permission controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$Sell Enterprise$q$, $q$$169/user/month$q$, $q$Billed annually (higher on month-to-month)$q$, $q$["Everything in Professional","Multiple sales pipelines","Custom roles and advanced permissions","Audit logs","Enhanced integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Zendesk Sell is a cloud-based sales CRM built by Zendesk to help sales teams organize contacts, track deals, and manage the sales cycle from a single, visual workspace. The product began life as Base CRM, a mobile-first CRM that Zendesk acquired in 2018 and folded into its customer experience platform, pairing pipeline management with the calling, email, and reporting tools sales reps use daily.$q$, $q$At its core, Sell centers on a drag-and-drop pipeline where deals move through customizable stages, with each deal card surfacing contact details, deal value, and a running activity feed. Built-in click-to-dial calling, email sync with open and click tracking, and text messaging let reps log outreach without switching apps, while dashboards and forecasting tools give managers visibility into pipeline health and expected revenue.$q$, $q$Because Sell shares a parent company with Zendesk's help desk products, it is positioned as the sales counterpart to a broader customer experience suite: teams already running Zendesk Support or the Zendesk Suite can view sales and support history for the same customer side by side. Sell also runs as a standalone product, competing for smaller sales teams' budgets against dedicated CRMs like Pipedrive, HubSpot, and Salesforce Essentials.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$who-zendesk-sell-is-for$q$, $q$Who Zendesk Sell Is For$q$, 2, ARRAY[$q$Small and mid-sized sales teams that want a CRM they can set up quickly and learn without a lengthy onboarding project are a strong fit for Sell. Its visual pipeline and straightforward contact records mirror how many reps already think about deal flow, so teams can move off spreadsheets or a basic contact manager with minimal retraining.$q$, $q$Field and phone-heavy sales reps benefit from Sell's mobile-first heritage: the app carries over Base CRM's geolocation-based visit tracking, offline access, and full pipeline management on the go, which makes it appealing to outside sales teams and account executives who spend limited time at a desk.$q$, $q$Organizations already using Zendesk Support or the Zendesk Suite for customer service are natural candidates, since Sell shares a login, billing relationship, and customer record context with those products, letting sales and support see the same account history without a separate integration project.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with highly complex, multi-department sales processes may find Sell's customization ceiling lower than platforms like Salesforce or Microsoft Dynamics 365, particularly around territory management, complex approval workflows, and deep custom object modeling.$q$, $q$Teams that rely heavily on marketing automation, such as multi-step nurture campaigns, landing page builders, or advanced lead-scoring models beyond what Sell's AI features offer, will likely need a dedicated marketing platform alongside or instead of Sell.$q$, $q$Budget-conscious teams should weigh the jump between tiers carefully: several of Sell's more advanced capabilities, including sales forecasting, custom fields, and permission controls, are gated behind the Growth, Professional, or Enterprise plans, and add-ons can increase the effective per-seat cost.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Sell's foundation is deal and contact management built around a customizable, drag-and-drop pipeline that supports multiple pipelines for different sales motions or teams. Each deal record keeps contact details, notes, documents, and a chronological activity feed together, so reps do not need to hunt across separate tools for context on a prospect.$q$, $q$Communication tools are built directly into the platform: click-to-dial calling with automatic logging and recording, email sync with templates and tracking, and text messaging all attach to the relevant contact or deal automatically. On top of this, Sell adds AI-assisted lead scoring to help reps prioritize the prospects most likely to convert, plus rule-based workflow automation for task assignment and follow-up reminders.$q$, $q$For visibility, Sell provides prebuilt and customizable reporting dashboards covering pipeline stage conversion, rep activity, and revenue forecasting, so managers can spot bottlenecks without building reports from scratch. An open API and a marketplace of prebuilt integrations extend the platform to other tools in a team's stack, including native integration with Zendesk's customer service products.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab650234-f963-4681-8c8b-6976b1473d49', $q$the-zendesk-sell-experience$q$, $q$The Zendesk Sell Experience$q$, 2, ARRAY[$q$Day to day, Sell's interface leans on the same clean, uncluttered design sensibility Zendesk applies across its products: the pipeline view is the default home screen for most reps, and moving a deal between stages is a single drag-and-drop action rather than a multi-click form. New users generally reach basic proficiency quickly, since the core workflows of adding a contact, logging a call, and advancing a deal require little training.$q$, $q$The mobile apps are a differentiator carried over from Base CRM's mobile-first origins, offering full pipeline access, offline support, and location-aware check-ins for field reps, which makes the experience feel consistent whether a rep is at a desk or visiting a client. Email and calling tools are woven into the same screens as deal and contact records, reducing the need to tab between a CRM and separate communication apps.$q$, $q$Teams that already use Zendesk for customer service tend to have the smoothest experience, since account setup, billing, and customer records can be shared across products. Teams evaluating Sell as a standalone CRM should expect a lighter, more opinionated tool than enterprise-grade platforms, trading some configurability for faster setup and a gentler learning curve.$q$]::text[], 4);
