INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Invoicing & Estimates$q$, $q$Create customizable, professional invoices and estimates, with support for progress invoicing and recurring billing schedules.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Expense Tracking & Receipt Autoscan$q$, $q$Log expenses manually or scan receipts to automatically extract line-item details and attach them to transactions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Bank Feeds & Reconciliation$q$, $q$Connect bank and credit card accounts to import transactions automatically and reconcile them against the books using configurable matching rules.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Multi-Currency Support$q$, $q$Bill and get paid in multiple currencies with automatic exchange-rate updates and gain/loss tracking for international transactions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Inventory Management$q$, $q$Track stock levels, warehouses, and item costs, with purchase and sales orders tied directly to inventory movement.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Project & Time Billing$q$, $q$Track billable hours and project expenses, then convert them directly into client invoices for accurate project profitability.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Client Portal$q$, $q$Give customers a self-service portal to view estimates and invoices, add comments, and pay online.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Custom Workflows & Automation$q$, $q$Build rule-based automations for approvals, reminders, and notifications to reduce repetitive manual bookkeeping work.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Financial Reporting$q$, $q$Generate over 50 built-in reports covering cash flow, profit and loss, balance sheets, and tax summaries, with custom report options on higher plans.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('970dd292-16fa-475f-996d-e50070df18a1', $q$Zoho & Third-Party Integrations$q$, $q$Sync data natively with Zoho CRM, Zoho Inventory, and Zoho Analytics, plus payment gateways and e-commerce platforms like Shopify and PayPal.$q$, 9);
