INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Omnichannel Communication$q$, $q$Unified SalesInbox plus built-in telephony, live chat, and social media channels for tracking customer conversations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Custom Modules & Deluge Functions$q$, $q$Extend the data model with custom modules, fields, and scripted functions for business-specific logic.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Reporting & Analytics$q$, $q$Standard dashboards and custom reports, with deeper analytics available via Zoho Analytics on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Territory & Multi-Currency Management$q$, $q$Assign territories and manage deals across multiple currencies for regional and international sales teams.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Marketing Automation Integration$q$, $q$Connects with Zoho Campaigns and Zoho Marketing Automation for lead nurturing and segmentation.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Mobile Apps$q$, $q$Native iOS and Android apps for record access, activity logging, and business-card scanning on the go.$q$, 9);
