INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Deep native integration with the wider Zoho One suite (Books, Desk, Campaigns, Analytics)$q$, 1);
