INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$AI (Zia) and automation are available on mid-tier plans, not reserved solely for the top tier$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca9138f2-35fd-49cf-8af2-819fa2691854', $q$Strong multi-currency, multi-language, and territory management for global sales teams$q$, 4);
