INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('74c8afcd-fff1-4116-8c21-aa7ea3ed5869', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Drag-and-drop form builder$q$, $q$Assemble forms visually using more than 30 field types, including file uploads, signatures, geolocation, and payment fields, with no coding required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$AI Assistant (Zia)$q$, $q$Generate a full form from a plain-language description, convert a photographed paper form into a digital one, or auto-fill fields from scanned documents.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Custom themes and branding$q$, $q$Apply logos, colors, fonts, and custom domains to published forms so they match your organization's branding.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Conditional logic and multi-page forms$q$, $q$Show or hide fields and pages based on prior answers to create dynamic, personalized form flows.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Multi-level approval workflows$q$, $q$Route submissions through configurable approval chains for use cases like expense requests, leave applications, and purchase orders.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Reports and data views$q$, $q$Review submissions in list or Kanban views with custom filters, and schedule automated exports to CSV or PDF.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Payment collection$q$, $q$Accept payments directly within forms through integrations with Stripe, PayPal, Square, and other gateways.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Native Zoho and third-party integrations$q$, $q$Send submission data automatically into Zoho CRM, Zoho Creator, Salesforce, Google Sheets, Slack, and other connected apps.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Webhooks and REST API$q$, $q$Push form data to custom systems or trigger external processes using webhooks and Zoho Forms' API.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Mobile apps for iOS and Android$q$, $q$Collect and review form submissions on the go, including offline data collection that syncs once reconnected.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Generous free plan and low-cost entry tier for individuals and small teams$q$, 0);
