INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Does Zoho Forms have a free plan?$q$, $q$Yes. The free plan allows one user, up to 3 forms, and 500 submissions per month, with basic themes and limited integrations.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Can Zoho Forms collect payments?$q$, $q$Yes, paid plans support payment collection through gateways such as Stripe, PayPal, and Square directly within a form.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Does Zoho Forms integrate with Zoho CRM and other Zoho apps?$q$, $q$Yes, Zoho Forms natively integrates with Zoho CRM, Zoho Creator, Zoho Flow, Zoho Sheet, and other apps in the Zoho One suite, in addition to third-party tools like Salesforce and Slack.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Is Zoho Forms suitable for HIPAA-compliant data collection?$q$, $q$Zoho Forms offers HIPAA-compliant form features, including encryption and audit trails, on its Premium plan.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Does Zoho Forms offer an API?$q$, $q$Yes, Zoho Forms provides a REST API along with webhooks so submission data can be sent to or pulled from external systems.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Event registration and check-in$q$, $q$Build registration forms with payment collection, then use the mobile app to check in attendees on-site.$q$, $q$Event organizers and marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$HR onboarding and approvals$q$, $q$Collect new-hire paperwork and route leave or expense requests through multi-level approval workflows.$q$, $q$HR and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('dd3c3df9-d594-426d-bdb3-8cf09852fd57', $q$Customer feedback and surveys$q$, $q$Create branded surveys and feedback forms, then analyze responses using built-in report views and filters.$q$, $q$Small businesses and customer support teams$q$, 2);
