INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Gantt Charts$q$, $q$Interactive Gantt charts with task dependencies, critical path analysis, and drag-and-drop rescheduling for traditional project planning.$q$, 0);
