INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Time Tracking & Timesheets$q$, $q$Built-in timers and timesheet logging that tie directly into project budgets and client billing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Blueprint Workflow Automation$q$, $q$A visual, no-code workflow builder for automating task transitions, approvals, and status updates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Project Budgeting$q$, $q$Tools to set budgets by cost or hours and track actuals against forecasts in real time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Resource Utilization Charts$q$, $q$Visual dashboards showing team workload and capacity to help balance assignments across projects.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Issue Tracking$q$, $q$An integrated bug and issue tracker for logging, prioritizing, and resolving problems alongside project tasks.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Zia AI Assistant$q$, $q$Zoho's AI layer offers automated summaries and smart suggestions to speed up routine project management tasks.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Client Portal$q$, $q$A dedicated portal for sharing project progress and files with external clients and stakeholders.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', $q$Zoho Ecosystem Integrations$q$, $q$Native connections to Zoho CRM, Books, Desk, and Sprints, plus third-party tools like Slack, Teams, and Power BI.$q$, 9);
