INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('96b25c45-e39f-4efc-ab12-25f3b2c786c6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Resume Parsing$q$, $q$Automatically extracts candidate details from uploaded resumes to build structured profiles and speed up data entry.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Multi-Channel Job Posting$q$, $q$Publish openings to job boards such as Indeed, LinkedIn, and Naukri, plus the careers site, directly from the platform.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Zia AI Assistant$q$, $q$AI-powered assistant that helps draft job descriptions, suggest candidate matches, and generate email or SMS content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Interview Scheduling$q$, $q$Coordinate interviews with calendar integrations, self-scheduling links, and automated reminders for candidates and interviewers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Candidate and Client Portals$q$, $q$Dedicated portals let candidates track application status and let staffing agency clients review shortlisted candidates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Workflow Automation and Blueprints$q$, $q$Automate repetitive tasks like status updates and notifications, and enforce standardized hiring processes with blueprints.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Assessments and Background Checks$q$, $q$Integrate skills assessments and background-check providers into the hiring pipeline on higher-tier plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Reporting and Analytics$q$, $q$Standard and custom reports and dashboards track pipeline health, time-to-hire, and source-of-hire metrics.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Zoho Ecosystem Integration$q$, $q$Connects natively with Zoho CRM, Zoho People, and Zoho Analytics, plus 50-plus third-party integrations.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Mobile Apps$q$, $q$iOS and Android apps let recruiters manage candidates, scan resumes, and review interviews from their phones.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Genuinely usable free plan with no time limit, good for very small hiring volumes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Pricing is significantly lower than many enterprise ATS platforms at comparable plan tiers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Separate Staffing Agency and Corporate HR editions tailor the workflow to each use case$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Deep customization through custom fields, layouts, blueprints, and automation rules$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Strong native integration with the wider Zoho ecosystem (CRM, People, Analytics)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Interface density and configuration options create a learning curve for new admins$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Free and entry-level plans have limited active job counts and no AI features$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Add-ons like video interviews and client portals can push real costs well above sticker price$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Deeper enterprise compliance and global HRIS capabilities may lag specialized platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Two-edition structure (Corporate HR vs Staffing Agency) can be confusing when comparing plans$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Is Zoho Recruit free to use?$q$, $q$Yes, Zoho Recruit offers a free-forever plan limited to a single active job posting with basic candidate management, job posting, and interview scheduling. Paid plans remove that limit and add features like AI candidate matching, advanced reporting, and portals.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$What is the difference between the Corporate HR and Staffing Agency editions?$q$, $q$The Corporate HR edition is built for internal talent acquisition teams hiring for their own company, while the Staffing Agency edition adds features for managing multiple client accounts, job orders, and candidate submittals. Pricing and job limits differ between the two editions at each plan tier.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Does Zoho Recruit include AI features?$q$, $q$Yes, Zoho Recruit includes Zia, an AI assistant that can help draft job descriptions and emails, suggest candidate matches, and support automated screening; AI features are concentrated in the Professional and Enterprise plans rather than the free tier.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Can Zoho Recruit integrate with other HR or CRM tools?$q$, $q$Zoho Recruit integrates natively with other Zoho products such as Zoho CRM, Zoho People, and Zoho Analytics, and connects to a range of third-party job boards, background-check providers, and communication tools.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Is there a mobile app for Zoho Recruit?$q$, $q$Yes, Zoho Recruit provides native mobile apps for iOS and Android that let recruiters manage candidates, review interview schedules, and scan resumes from a mobile device.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Building an internal hiring pipeline$q$, $q$An in-house HR team sets up job postings, candidate pipelines, and interview scheduling to manage recurring hiring needs without spreadsheets or shared inboxes.$q$, $q$Small and midsize company HR/talent acquisition teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Managing multi-client staffing operations$q$, $q$A staffing agency tracks job orders from multiple client companies, submits candidates against specific requisitions, and shares shortlists through a client portal.$q$, $q$Recruiting and staffing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Centralizing a searchable talent pool$q$, $q$A recruiting team builds a long-term candidate database with parsed resumes and tags so past applicants can be resurfaced for future openings.$q$, $q$Recruiters handling repeat or high-volume hiring$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Connecting recruiting to the broader HR stack$q$, $q$A company already using Zoho People or Zoho CRM extends its workflow into recruiting, syncing hired candidates and client data across the Zoho ecosystem.$q$, $q$Organizations standardized on the Zoho product suite$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Free$q$, $q$$0$q$, $q$Free forever$q$, $q$["1 active job","Basic candidate management","Job posting to free boards","Email handling","Interview scheduling"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Standard$q$, $q$Around $25 per recruiter/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["Increased active job limit","Candidate search and CV management","Premium job board posting","Social recruiting","Standard reports and dashboards","50+ integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Professional$q$, $q$Around $50 per recruiter/month (billed annually)$q$, $q$Monthly or annual$q$, $q$["AI candidate screening","Advanced analytics and custom reports","Candidate portals","Assessments and background check integrations","Advanced security controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$Enterprise$q$, $q$Around $75 per recruiter/month (billed annually, Staffing Agency edition)$q$, $q$Monthly or annual$q$, $q$["Custom roles and profiles","Custom functions and buttons","Client and recruitment portals","Blueprints and territory management","Advanced assignment rules"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Zoho Recruit is a cloud-based applicant tracking system (ATS) and recruiting CRM built by Zoho Corporation, the same company behind Zoho CRM, Zoho People, and the wider Zoho One suite. It's designed to cover the full hiring lifecycle, from posting a job and sourcing candidates through parsing resumes, scheduling interviews, running assessments, and moving a candidate to an offer, all from a single workspace.$q$, $q$The product ships in two distinct editions that share the same core engine but present different plan structures and job limits: a Corporate HR edition aimed at internal talent acquisition teams, and a Staffing Agency edition built around managing multiple clients, submittals, and commission-style workflows. Both editions sit on Zoho's broader low-code platform, so the underlying customization tools (custom fields, layouts, blueprints, functions) are shared across the company's other apps.$q$, $q$In the crowded ATS market, Zoho Recruit is generally positioned as a value-for-money option: it offers a genuinely usable free tier, mid-market pricing well below many enterprise HR suites, and native integration with the rest of the Zoho ecosystem for teams already standardized on it. That combination makes it a common choice for small businesses, growing HR teams, and independent or boutique staffing agencies rather than large multinational enterprises with complex compliance needs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$who-zoho-recruit-is-for$q$, $q$Who Zoho Recruit Is For$q$, 2, ARRAY[$q$Zoho Recruit fits small and midsize in-house HR or talent acquisition teams that need a structured ATS without enterprise-level licensing costs. Companies hiring for a handful to a few dozen open roles at a time, and that want candidate pipelines, interview scheduling, and reporting in one tool, are a natural match, especially once they outgrow spreadsheets or shared inboxes for tracking applicants.$q$, $q$Recruiting and staffing agencies are an equally strong fit, given the purpose-built Staffing Agency edition. Agencies that need to track multiple client companies, manage submittals against specific job orders, and keep a searchable talent pool for repeat placements can lean on Zoho Recruit's CRM-style contact and account structure alongside the standard ATS pipeline.$q$, $q$Organizations already invested in the Zoho ecosystem, particularly Zoho One, Zoho CRM, or Zoho People, get outsized value because Zoho Recruit connects natively to those products for hand-offs like converting a hired candidate into an employee record or syncing client and deal data with sales. Budget-conscious teams that want to start free and scale into paid tiers as hiring volume grows are also well served by the plan structure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-country hiring compliance, deep background-check chains, or heavy union/labor requirements may find Zoho Recruit's built-in coverage thinner than dedicated enterprise HCM or ATS suites that specialize in global compliance and identity verification out of the box.$q$, $q$Teams that prioritize a highly polished, minimal-configuration user experience over flexibility may find the interface dense at first. Like most Zoho products, Recruit exposes a large number of settings, modules, and customization screens, and new admins often need real ramp-up time to configure it well rather than getting a guided, opinionated setup.$q$, $q$Companies that need deep, industry-specific workflows out of the box, such as healthcare credentialing, complex union hiring rules, or highly specialized executive search processes, may be better served by niche ATS platforms built specifically around those workflows rather than a general-purpose tool like Zoho Recruit.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Core ATS functionality includes resume parsing that extracts candidate details automatically, multi-channel job posting to boards like Indeed, LinkedIn, and Naukri, a searchable candidate database, and a hosted candidate portal so applicants can track their own status. A client portal (on paid tiers) lets staffing agencies share shortlists directly with hiring companies.$q$, $q$Zoho layers AI throughout the product via Zia, its AI assistant, which can help draft job descriptions, suggest candidate matches, screen resumes, and generate email or SMS content. Interview scheduling includes calendar integrations and self-scheduling links, and higher tiers add candidate assessments, background-check integrations, and video interviewing add-ons.$q$, $q$On the operations side, Zoho Recruit offers workflow automation, blueprints for enforcing standardized hiring stages, assignment rules for routing candidates to recruiters, and customizable reports and dashboards for pipeline and source-of-hire analytics. It also connects to the rest of the Zoho suite (Zoho CRM, Zoho People, Zoho Analytics) as well as a marketplace of third-party integrations for HRIS, background checks, and communication tools.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26be16cd-25ce-4578-8910-70ede05cb0ab', $q$the-zoho-recruit-experience$q$, $q$The Zoho Recruit Experience$q$, 2, ARRAY[$q$Getting started with Zoho Recruit is quick at a basic level, since the free plan lets a team post a job and start tracking candidates immediately, but unlocking its full value takes more deliberate setup: configuring custom fields, pipeline stages, email templates, and automation rules to match a specific hiring process.$q$, $q$Day to day, recruiters work from a candidate- and job-centric dashboard, moving applicants through pipeline stages, logging calls and emails, and using the mobile apps for iOS and Android to review candidates, scan resumes on the go, or manage interviews from a phone. The interface follows the same visual language as other Zoho apps, which helps existing Zoho users but can feel unfamiliar to teams coming from more consumer-style HR tools.$q$, $q$Support is available through in-app help, a searchable knowledge base, community forums, and live chat or phone on paid plans, with response depth generally scaling with plan tier. Overall, the experience rewards teams willing to invest time in configuration, delivering a capable, highly customizable ATS at a price point well below most enterprise alternatives.$q$]::text[], 4);
