INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0bab077d-6e0b-45aa-9bbf-e0c11e6547d8', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Unlimited domestic calling$q$, $q$Unlimited inbound and outbound calling across the US and Canada on core plans, with metered options available for lighter usage.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$SMS and MMS messaging$q$, $q$Send and receive text and multimedia messages from a business number alongside voice calls.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$AI Companion call summaries$q$, $q$Automatically generated call summaries, highlights, and follow-up action items powered by Zoom's AI Companion.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$AI receptionist$q$, $q$An AI-driven virtual receptionist that can greet callers, answer common questions, and route calls or take messages.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Auto attendants and call queues$q$, $q$Multi-level auto attendants and call queues route incoming calls to the right person, department, or voicemail.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Voicemail transcription$q$, $q$Voicemails are automatically transcribed to text and delivered with the audio recording.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Call recording and analytics$q$, $q$On-demand or automatic call recording plus dashboards for monitoring call volume, quality, and handling.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Desk phone and softphone support$q$, $q$Works with certified desk phones from partners like Poly, Yealink, and Cisco, or as a softphone in the Zoom desktop and mobile apps.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Centralized admin portal$q$, $q$A web-based admin console for provisioning numbers, assigning devices, and configuring call routing across the organization.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Zoom Phone Local Survivability$q$, $q$Keeps core calling functions available at a site even during an internet or network outage.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Unified experience with Zoom Meetings and Zoom Team Chat under one app and account$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Unlimited domestic calling included on core US & Canada plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$AI Companion adds call summaries and an AI receptionist without third-party add-ons$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Flexible device support across desktop, mobile, browser, and certified desk phones$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Enterprise-grade uptime SLA and Local Survivability for outage resilience$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Best value is tied to adopting the broader Zoom Workplace suite rather than as a pure standalone phone line$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$International calling coverage and rates vary by country and can add cost beyond the base subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Advanced contact center features require Zoom's separate Contact Center product$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Free trial is limited mainly to the US & Canada Unlimited plan, not all tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Call quality depends on the customer's internet connection, as with any VoIP service$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$What is Zoom Phone?$q$, $q$Zoom Phone is Zoom's cloud-based business phone (VoIP) system that lets teams make and receive calls from the Zoom desktop app, mobile app, browser, or certified desk phones.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Does Zoom Phone offer a free trial?$q$, $q$Zoom offers a free trial on select Zoom Phone plans, primarily the US & Canada Unlimited plan, so teams can test call quality and features before subscribing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$How much does Zoom Phone cost?$q$, $q$Pricing starts around $15 per user per month for the US & Canada Unlimited plan when billed annually, with higher tiers like Global Select and Workplace bundles (Pro Plus, Business Plus) priced higher based on included features.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Can I use my existing desk phones with Zoom Phone?$q$, $q$Yes, Zoom Phone supports a range of certified desk phones from vendors such as Poly, Yealink, and Cisco, alongside softphone use in the Zoom app.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Is Zoom Phone suitable for international calling?$q$, $q$Zoom Phone offers a Global Select plan with unlimited calling in a selection of supported countries, plus metered international rates for calls outside the included plan, so availability should be checked against a business's specific countries of operation.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Replacing a legacy office PBX$q$, $q$Moving an office from on-premises phone hardware to a cloud system that provisions numbers and routing entirely through software.$q$, $q$IT teams at small and mid-sized businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Equipping distributed and remote teams$q$, $q$Giving remote or hybrid employees a business phone number and calling capability through the Zoom app on their laptop or phone.$q$, $q$Remote-first companies and distributed teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Consolidating meetings, chat, and calling$q$, $q$Standardizing on one Zoom Workplace account for video meetings, team chat, and phone calls to reduce the number of separate collaboration tools.$q$, $q$Organizations already using Zoom Meetings$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Front-desk and department call routing$q$, $q$Using auto attendants, call queues, and an AI receptionist to route incoming calls to the correct team or extension without a live operator.$q$, $q$Multi-location businesses and customer-facing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$US & Canada Metered$q$, $q$Base fee plus per-minute outbound rate$q$, $q$monthly or annual$q$, $q$["Pay-per-minute outbound domestic calling","Call recording","IVR and auto attendant","Voicemail with transcription"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$US & Canada Unlimited$q$, $q$$15/user/month$q$, $q$annual$q$, $q$["Unlimited domestic calling","SMS/MMS messaging","Metered international calling","Domestic phone number included"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Global Select$q$, $q$$20/user/month$q$, $q$annual$q$, $q$["Unlimited calling in one of 48+ supported countries","Standalone DID number","Built for international teams"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$Pro Plus (Zoom Workplace bundle)$q$, $q$$18.33/user/month$q$, $q$annual$q$, $q$["Unlimited US & Canada calling","Zoom Meetings up to 30 hours, 100 participants","Unlimited AI Companion","Team Chat, Mail, Calendar, Whiteboard"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Zoom Phone is the cloud-based business phone system built by Zoom Communications, the company best known for its video conferencing platform. It replaces traditional on-premises PBX hardware with a software-defined phone system that runs on Zoom's global cloud infrastructure, letting employees make and receive calls from a desktop app, mobile app, browser, or a certified desk phone using the same account they already use for Zoom Meetings and Zoom Team Chat.$q$, $q$The product is positioned as one part of the broader Zoom Workplace suite, so calling, video, chat, whiteboard, and scheduling live inside a single client and a single admin console rather than as separate purchased tools. Core telephony capabilities include auto attendants, call queues, IVR menus, voicemail with transcription, call recording, and supervised or blind call transfers, along with an AI Companion layer that can summarize calls and generate follow-up tasks.$q$, $q$Because it is delivered entirely over the internet, Zoom Phone can be provisioned for a new employee in minutes and extended to new offices or remote workers without installing physical phone lines, which is the main practical difference from a legacy PBX or a POTS line-based system.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$who-zoom-phone-is-for$q$, $q$Who Zoom Phone Is For$q$, 2, ARRAY[$q$Zoom Phone is best suited to organizations that already use Zoom Meetings or are considering Zoom Workplace as their primary collaboration suite, since the phone system is designed to sit alongside those tools rather than as a fully standalone product. Small and mid-sized businesses that want one vendor for meetings, chat, and calling — instead of stitching together separate video and telephony providers — are a natural fit.$q$, $q$It also suits distributed or remote-first teams that need employees to have a business phone number without shipping desk phones, since calls can be placed from a laptop or smartphone using the Zoom app. IT teams managing multi-location businesses benefit from the centralized web admin portal, which handles number assignment, call routing, and device management from one dashboard.$q$, $q$Larger enterprises with compliance or uptime requirements can also use Zoom Phone, since it offers five-nines (99.999%) uptime SLAs on qualifying plans and features like Local Survivability to keep calling available during an internet outage, plus SSO and advanced compliance controls on higher tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Businesses that need calling as a narrowly focused, low-cost product — rather than a bundled communications suite — may find dedicated VoIP providers a better fit, since much of Zoom Phone's value and pricing is tied to the wider Zoom Workplace ecosystem. Teams that have no interest in Zoom Meetings or Zoom Chat may end up paying for adjacent functionality they will not use.$q$, $q$Companies with heavy call center requirements, such as advanced omnichannel routing, workforce management, or deep CRM-embedded contact center workflows, are generally better served by Zoom's separate Contact Center product or a purpose-built contact center platform, since standard Zoom Phone is oriented toward general business calling rather than high-volume support operations.$q$, $q$Organizations needing extensive international coverage beyond the countries included in Zoom's Global Select plan, or that require calling in dozens of markets simultaneously, should verify country-by-country availability and rate cards before committing, since international calling can add meaningful metered costs on top of the base subscription.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Zoom Phone provides unlimited domestic calling and SMS/MMS on its core plans, along with configurable call routing tools such as auto attendants, call queues, IVR menus, and shared/delegate call handling so front-desk and support scenarios can be modeled without extra hardware. Voicemail transcription, call recording, and call analytics give administrators visibility into how calls are handled across the organization.$q$, $q$AI Companion adds AI-generated call summaries, action items, and (on eligible plans) an AI receptionist that can greet callers, answer common questions, and route calls or take messages automatically. Devices are flexible: users can make calls from the Zoom desktop and mobile apps, a browser, or certified desk phones from partners like Poly, Yealink, and Cisco.$q$, $q$Administrative features include a centralized web portal for provisioning numbers, assigning devices, and setting routing rules; number porting; e911 emergency calling support; and, on higher-tier plans, single sign-on, multi-region data residency, and Local Survivability for continued calling during network disruptions.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', $q$the-zoom-phone-experience$q$, $q$The Zoom Phone Experience$q$, 2, ARRAY[$q$Day to day, using Zoom Phone feels like an extension of the Zoom app users already know: calling lives in the same client as meetings and chat, so switching from a chat thread to a voice call or escalating a call into a video meeting happens without leaving the app. This familiarity tends to shorten onboarding for teams already on Zoom Workplace.$q$, $q$Call quality and reliability are generally well regarded, backed by Zoom's global carrier network and uptime SLAs, though as with any VoIP service actual call quality depends on the strength and stability of the user's internet connection. The admin experience is commonly described as straightforward, with bulk provisioning and clear routing configuration reducing the IT overhead of managing phone numbers across an organization.$q$, $q$The main adjustment for teams moving from a traditional desk-phone PBX is cultural rather than technical: users need to get comfortable making and receiving business calls from a laptop or phone app, and administrators need to plan network bandwidth and E911 address configuration carefully during rollout to avoid call quality or emergency-routing issues.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('96e91f43-5f01-4104-b90d-be66d79b5e88', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
